import React, {useEffect} from 'react';
import {AccessibilityInfo, StyleSheet, Text} from 'react-native';
import Animated, {runOnJS, useAnimatedStyle, useSharedValue, withDelay, withSequence, withSpring, withTiming} from 'react-native-reanimated';
import * as Haptics from 'expo-haptics';
export function SaveSuccessOverlay({onDone}: {onDone: () => void}) {
  const scale = useSharedValue(0); const opacity = useSharedValue(0);
  useEffect(() => {
    Haptics.notificationAsync(Haptics.NotificationFeedbackType.Success);
    AccessibilityInfo.announceForAccessibility('Saved');
    opacity.value = withTiming(1, {duration: 120});
    scale.value = withSequence(withSpring(1.18, {damping: 10}), withSpring(1, {damping: 14}));
    opacity.value = withDelay(1200, withTiming(0, {duration: 180}, (finished) => { if (finished) runOnJS(onDone)(); }));
  }, [onDone, opacity, scale]);
  const style = useAnimatedStyle(() => ({opacity: opacity.value, transform: [{scale: scale.value}]}));
  return <Animated.View pointerEvents="none" style={[styles.overlay, style]} accessibilityRole="text"><Text style={styles.check}>✓</Text><Text style={styles.text}>Saved</Text></Animated.View>;
}
