import React from 'react';
import {Marker} from 'react-native-maps';
import {View, Text, StyleSheet} from 'react-native';
function haversine(a: {latitude:number; longitude:number}, b: {latitude:number; longitude:number}) { const R = 6371; const dLat = (b.latitude - a.latitude) * Math.PI / 180; const dLon = (b.longitude - a.longitude) * Math.PI / 180; const lat1 = a.latitude * Math.PI / 180; const lat2 = b.latitude * Math.PI / 180; const x = Math.sin(dLat/2)**2 + Math.sin(dLon/2)**2 * Math.cos(lat1) * Math.cos(lat2); return 2 * R * Math.asin(Math.sqrt(x)); }
export function DistanceLabel({a, b}: {a: any; b: any}) { const mid = {latitude: (a.latitude + b.latitude)/2, longitude: (a.longitude + b.longitude)/2}; const km = haversine(a, b); return (<Marker coordinate={mid} anchor={{x:0.5, y:0.5}}><View style={s.label}><Text style={s.text}>{km.toFixed(1)} km</Text></View></Marker>); }
const s = StyleSheet.create({label:{backgroundColor:'rgba(0,0,0,0.8)', paddingHorizontal:8, paddingVertical:4, borderRadius:6}, text:{color:'#fff', fontSize:12, fontVariant:['tabular-nums']}});

