import React, {useEffect} from 'react';
import {StyleSheet, View, Text} from 'react-native';
import {Canvas, Path, Skia} from '@shopify/react-native-skia';
import {useSharedValue, withTiming, useDerivedValue} from 'react-native-reanimated';
export function RadarChart({values, labels, size = 240}: {values: number[]; labels: string[]; size?: number}) {
  const p = useSharedValue(0);
  useEffect(() => { p.value = withTiming(1, {duration: 700}); }, [values]);
  const cx = size/2; const cy = size/2; const r = size/2 - 30;
  const fillPath = useDerivedValue(() => { const path = Skia.Path.Make(); const count = values.length; values.forEach((v, i) => { const angle = (i / count) * Math.PI * 2 - Math.PI/2; const px = cx + Math.cos(angle) * r * v * p.value; const py = cy + Math.sin(angle) * r * v * p.value; if (i === 0) path.moveTo(px, py); else path.lineTo(px, py); }); path.close(); return path; });
  const grid = Skia.Path.Make(); [0.25, 0.5, 0.75, 1].forEach(rr => { values.forEach((_, i) => { const angle = (i / values.length) * Math.PI * 2 - Math.PI/2; const px = cx + Math.cos(angle) * r * rr; const py = cy + Math.sin(angle) * r * rr; if (i === 0) grid.moveTo(px, py); else grid.lineTo(px, py); }); grid.close(); });
  return (<View style={{width: size, height: size}}><Canvas style={StyleSheet.absoluteFill}><Path path={grid} style='stroke' color='#2C2C2E' strokeWidth={1}/><Path path={fillPath} color='rgba(10,132,255,0.4)'/><Path path={fillPath} style='stroke' color='#0A84FF' strokeWidth={2}/></Canvas>{labels.map((l, i) => { const angle = (i / values.length) * Math.PI * 2 - Math.PI/2; const tx = cx + Math.cos(angle) * (r + 16) - 30; const ty = cy + Math.sin(angle) * (r + 16) - 8; return <Text key={i} style={[s.label, {left: tx, top: ty}]}>{l}</Text>; })}</View>);
}
