// FpsOverlay.tsx (dev only)
import React, {useState} from 'react';
import {StyleSheet, View, Text} from 'react-native';
import {useFrameCallback, runOnJS, useSharedValue} from 'react-native-reanimated';
export function FpsOverlay() { const [fps, setFps] = useState(0); const lastT = useSharedValue(0); const acc = useSharedValue(0); const count = useSharedValue(0); useFrameCallback(({timeSinceFirstFrame}) => { const dt = timeSinceFirstFrame - lastT.value; lastT.value = timeSinceFirstFrame; acc.value += dt; count.value += 1; if (acc.value >= 1000) { runOnJS(setFps)(Math.round((count.value / acc.value) * 1000)); acc.value = 0; count.value = 0; }}); if (!__DEV__) return null; return (<View style={s.box}><Text style={s.text}>{fps} fps</Text></View>); }
const s = StyleSheet.create({box:{position:'absolute', top:60, right:10, backgroundColor:'rgba(0,0,0,0.7)', padding:6, borderRadius:6, zIndex:9999}, text:{color:'#30D158', fontVariant:['tabular-nums'], fontSize:12}});
